inline constexpr std::size_t kStrategyCount = sizeof(kStrategies) / sizeof(kStrategies[0]);

inline constexpr int kGeneralStrategyIndex = 0;

inline constexpr std::size_t kBaseStrategyCount =
	[]() constexpr -> std::size_t {
		std::size_t count = 0;
		for (const StrategyDefinition& strategy : kStrategies)
			if (!strategy.isExtra)
				++count;
		return count;
	}();

inline bool IsStrategyVisible(int strategyIndex, bool showExtraStrategies)
{
	if (strategyIndex < 0 || strategyIndex >= static_cast<int>(kStrategyCount))
		return false;
	if (showExtraStrategies)
		return true;
	return !kStrategies[static_cast<std::size_t>(strategyIndex)].isExtra;
}

inline int CountVisibleStrategies(bool showExtraStrategies)
{
	int count = 0;
	for (std::size_t i = 0; i < kStrategyCount; ++i)
		if (IsStrategyVisible(static_cast<int>(i), showExtraStrategies))
			++count;
	return count;
}

inline int GetVisibleStrategyAt(int visibleIndex, bool showExtraStrategies)
{
	int seen = 0;
	for (std::size_t i = 0; i < kStrategyCount; ++i)
	{
		if (!IsStrategyVisible(static_cast<int>(i), showExtraStrategies))
			continue;
		if (seen == visibleIndex)
			return static_cast<int>(i);
		++seen;
	}
	return -1;
}

inline int FindVisibleStrategyPosition(int strategyIndex, bool showExtraStrategies)
{
	if (!IsStrategyVisible(strategyIndex, showExtraStrategies))
		return -1;
	int position = 0;
	for (int i = 0; i < strategyIndex; ++i)
	{
		if (IsStrategyVisible(i, showExtraStrategies))
			++position;
	}
	return position;
}

inline std::string_view GetStrategyLabel(int strategyIndex)
{
	if (strategyIndex < 0 || strategyIndex >= static_cast<int>(kStrategyCount))
		return {};
	return kStrategies[static_cast<std::size_t>(strategyIndex)].label;
}

inline constexpr GameFilterValues GetGameFilterValues(GameFilterMode mode)
{
	switch (mode)
	{
	case GameFilterMode::Disabled:
		return kGameFilterModes[static_cast<std::size_t>(GameFilterMode::Disabled)];
	case GameFilterMode::All:
		return kGameFilterModes[static_cast<std::size_t>(GameFilterMode::All)];
	case GameFilterMode::Tcp:
		return kGameFilterModes[static_cast<std::size_t>(GameFilterMode::Tcp)];
	case GameFilterMode::Udp:
		return kGameFilterModes[static_cast<std::size_t>(GameFilterMode::Udp)];
	}
	return kGameFilterModes[static_cast<std::size_t>(kDefaultGameFilterMode)];
}

